def solve(arg1: dict) -> dict:
    nums = arg1.get('nums', [])
    target = arg1.get('target', 0)

    if not nums or target is None:
        return {'status': 'error', 'message': 'Payload is required.'}

    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return {'status': 'success', 'message': 'Quote negotiation initiated.', 'indices': (left, right)}
        if total < target:
            left += 1
        else:
            right -= 1

    return {'status': 'error', 'message': 'No solution found.'}
